                const data = await response.json();

                if (response.ok) {
                    showMessage(forgotPasswordMessage, 'success', data.message);
                    forgotPasswordForm.reset();
                } else {
                    showMessage(forgotPasswordMessage, 'error', data.error || 'An error occurred.');
