            resetPasswordLoading.style.display = 'block'; // Indicate validation is happening

            try {
                const response = await fetch('/api/reset-password-validate', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({ token }),
                });

                const data = await response.json();

                if (!response.ok) {
                    showMessage(resetPasswordMessage, 'error', data.error || 'Invalid or expired password reset link. Please request a new one.');
                    resetPasswordForm.style.display = 'none'; // Hide the form if token is invalid/expired
                } else {
                    // Token is valid, allow user to set new password
                    resetPasswordForm.style.display = 'block';
                }
            } catch (error) {
                console.error('Network error:', error);
                showMessage(resetPasswordMessage, 'error', 'Could not validate reset link. Please try again.');
                resetPasswordForm.style.display = 'none';
            } finally {
                resetPasswordLoading.style.display = 'none';
            }
        }

        // Reset Password Form Submission
        resetPasswordForm.addEventListener('submit', async (e) => {
            e.preventDefault();
            hideMessage(resetPasswordMessage);
            resetPasswordLoading.style.display = 'block';

            const newPassword = document.getElementById('new-password').value;
            const confirmPassword = document.getElementById('confirm-password').value;

            if (newPassword !== confirmPassword) {
                showMessage(resetPasswordMessage, 'error', 'Passwords do not match.');
                resetPasswordLoading.style.display = 'none';
                return;
