            // Password complexity requirements (client-side validation for better UX)
            // At least 8 characters, one uppercase, one lowercase, one number, one special character
            const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*()_+={}\[\]|\\:;"'<>,.?/~`])[A-Za-z\d!@#$%^&*()_+={}\[\]|\\:;"'<>,.?/~`]{8,}$/;
            if (!passwordRegex.test(newPassword)) {
                showMessage(resetPasswordMessage, 'error', 'Password must be at least 8 characters long, include an uppercase letter, a lowercase letter, a number, and a special character.');
                resetPasswordLoading.style.display = 'none';
                return;
            }

            try {
                const response = await fetch('/api/reset-password', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({ token, newPassword }),
                });

                const data = await response.json();

                if (response.ok) {
                    showMessage(resetPasswordMessage, 'success', data.message + ' Redirecting to login...');
                    resetPasswordForm.reset();
                    // Redirect to login page after a short delay for better UX
                    setTimeout(() => {
                        window.location.href = '/login'; // Assuming a /login endpoint
                    }, 3000); // 3-second delay
                } else {
                    showMessage(resetPasswordMessage, 'error', data.error || 'An error occurred during password reset.');
                }
            } catch (error) {
                console.error('Network error:', error);
                showMessage(resetPasswordMessage, 'error', 'Could not connect to the server. Please try again.');
            } finally {
                resetPasswordLoading.style.display = 'none';
            }
        });
    </script>
</body>
